import { execFile } from 'node:child_process';
import { mkdir, realpath, writeFile } from 'node:fs/promises';
import { posix, resolve } from 'node:path';
import { promisify } from 'node:util';
import { loadBrowserConfig } from './config/load.js';
import { projectPaths } from './project.js';
const execFileAsync = promisify(execFile);
export async function exportFirefoxPatch(path, cwd = process.cwd()) {
    if (!path || path === '.' || path === '..' || posix.isAbsolute(path) ||
        posix.normalize(path) !== path || path.startsWith('../') || path.includes('\\')) {
        throw new Error('Export path must be a safe relative Firefox path.');
    }
    const paths = await projectPaths(cwd);
    const source = await realpath(paths.firefoxSource);
    const config = await loadBrowserConfig(cwd);
    const { stdout } = await execFileAsync('git', ['-C', source, 'diff', '--binary', 'HEAD', '--', path], { maxBuffer: 16 * 1024 * 1024 });
    if (!stdout.trim())
        throw new Error(`No Firefox source changes found at ${path}.`);
    const patchDirectory = resolve(paths.projectDirectory, config.patches.directory);
    const target = resolve(patchDirectory, `${path.replaceAll('/', '__')}.patch`);
    await mkdir(patchDirectory, { recursive: true });
    await writeFile(target, stdout.endsWith('\n') ? stdout : `${stdout}\n`);
    return target;
}
